/**
 * API信息接口
 */
export interface ApiInfo {
    api: string;
    success: boolean;
    time: number;
    code?: string | number;
    msg?: string;
    traceId?: string;
    sid?: string;
}

/**
 * 错误位置信息接口
 */

export interface PosInfo {
    filename?: string;
    lineno?: string;
    colno?: string;
}

/**
 * 性能信息接口
 */
export interface PerformanceInfo {
    cfpt: number;
    ctti: number;
    t1?: number;
    t2?: number;
    t3?: number;
    t4?: number;
    t5?: number;
    t6?: number;
    t7?: number;
    t8?: number;
    t9?: number;
    t10?: number;
}

/**
 * 公共信息接口
 */
export interface CommonInfo {
    name: string;
    common: string;
}

/**
 * 自定义用户行为信息接口
 */

type BehaviorDataInfo = { name: string } | { message: string };
// name：行为名称，String类型，必填，最大长度20字符。
//message：行为内容，String类型，必填，最大长度200字符。

export interface BehaviorInfo {
    data: BehaviorDataInfo;
    page?: string;
}

// 类型别名：用于描述 URL 辅助器的类型
type UrlHelper = string | RegExp | UrlHelperFunction | any[];

// 函数签名：URL 辅助器函数的类型
type UrlHelperFunction = (url: string) => boolean;

// 函数签名：用于描述忽略函数的类型
type IgnoreFunction = (str: string) => boolean;

export interface ConfigObject {
    pid?: string;
    uid?: string;
    tag?: string;
    page?: string;
    enableSPA?: boolean;
    disableHook?: boolean;
    ignoreUrlCase?: boolean;
    disabled?: boolean;
    sample?: number;
    pvSample?: number;
    sendResource?: boolean;
    useFmp?: boolean;
    enableLinkTrace?: boolean;
    behavior?: boolean;
    autoSendPerf?: boolean;
    c1?: string;
    c2?: string;
    c3?: string;
    environment?: 'prod' | 'gray' | 'pre' | 'daily' | 'local';
    urlHelper?: UrlHelper;
    apiHelper?: UrlHelper;
    // 限制长度 40 且只会调用一次
    setUsername?: () => string;
    parseHash?: () => string;
    parseResponse?: (response: any) => any;
    ignore?: {
        ignoreUrls?: RegExp | IgnoreFunction[];
        ignoreApis?: RegExp | IgnoreFunction[];
        ignoreErrors?: RegExp | IgnoreFunction[];
        ignoreResError?: RegExp | IgnoreFunction[];
    };
}
